const allOf = function (name) { try { const items = $(name).all().map(function (i) { return i.json; }); if (items.length === 1 && Array.isArray(items[0])) return items[0]; return items; } catch (e) { return []; } };
const whealth   = allOf('Fetch Workflow Health');
const ehealth   = allOf('Fetch Endpoint Health');
const thresholds = allOf('Fetch Thresholds');

// Build threshold lookup: workflow-specific > endpoint-specific > default.
const byScope = { workflow: {}, endpoint: {}, default: null };
thresholds.forEach(function (t) {
  if (t.scope === 'default') byScope.default = t;
  else if (t.scope === 'workflow' && t.target_name) byScope.workflow[t.target_name] = t;
  else if (t.scope === 'endpoint' && t.target_name) byScope.endpoint[t.target_name] = t;
});
const defaults = byScope.default || { error_rate_warning_pct: 10, error_rate_critical_pct: 25, max_silence_minutes: 60, max_p95_ms: 30000, max_consecutive_down: 3 };

const alerts = [];
const nowHour = new Date().toISOString().slice(0, 13);  // YYYY-MM-DDTHH for aggregation_key

// === Workflow analysis ===
// Latest window per workflow.
const latestByWf = {};
whealth.forEach(function (h) {
  if (!latestByWf[h.workflow_id] || h.window_start > latestByWf[h.workflow_id].window_start) {
    latestByWf[h.workflow_id] = h;
  }
});
Object.keys(latestByWf).forEach(function (wid) {
  const h = latestByWf[wid];
  const thr = (h.workflow_name && byScope.workflow[h.workflow_name]) || defaults;
  const winAgeMin = (Date.now() - new Date(h.window_end).getTime()) / 60000;

  // Silent detection: 0 executions in latest window. We only alarm if windows BEFORE this
  // also show silence beyond the max_silence_minutes threshold — single 5-min gaps are normal.
  if (h.execution_count === 0) {
    const recent = whealth.filter(function (r) { return r.workflow_id === wid; }).slice(0, Math.ceil(thr.max_silence_minutes / 5));
    const allSilent = recent.length > 0 && recent.every(function (r) { return r.execution_count === 0; });
    if (allSilent && recent.length * 5 >= thr.max_silence_minutes) {
      alerts.push({
        severity: 'critical', alert_type: 'health_workflow_silent',
        title: '[' + (h.workflow_name || wid) + '] No executions in ' + (recent.length * 5) + ' minutes',
        message: 'Active workflow has had zero executions for at least ' + thr.max_silence_minutes + ' minutes. Possible scheduler stall, credential issue, or upstream dependency outage.',
        aggregation_key: 'health:silent:' + wid + ':' + nowHour,
        details: { workflow_id: wid, workflow_name: h.workflow_name, silent_for_minutes: recent.length * 5, threshold_minutes: thr.max_silence_minutes }
      });
    }
    return;
  }

  // Error rate evaluation.
  const errPct = parseFloat(h.error_rate_pct) || 0;
  if (errPct >= thr.error_rate_critical_pct) {
    alerts.push({
      severity: 'critical', alert_type: 'health_error_spike',
      title: '[' + (h.workflow_name || wid) + '] ' + errPct.toFixed(1) + '% error rate — CRITICAL',
      message: 'Error rate breached critical threshold (' + thr.error_rate_critical_pct + '%) in the latest 5-min window. ' + h.error_count + '/' + h.execution_count + ' failed.',
      aggregation_key: 'health:error:critical:' + wid + ':' + nowHour,
      details: { workflow_id: wid, workflow_name: h.workflow_name, error_rate_pct: errPct, error_count: h.error_count, execution_count: h.execution_count, threshold_pct: thr.error_rate_critical_pct }
    });
  } else if (errPct >= thr.error_rate_warning_pct) {
    alerts.push({
      severity: 'warning', alert_type: 'health_error_spike',
      title: '[' + (h.workflow_name || wid) + '] ' + errPct.toFixed(1) + '% error rate — warning',
      message: 'Error rate breached warning threshold (' + thr.error_rate_warning_pct + '%) in the latest 5-min window.',
      aggregation_key: 'health:error:warning:' + wid + ':' + nowHour,
      details: { workflow_id: wid, workflow_name: h.workflow_name, error_rate_pct: errPct, threshold_pct: thr.error_rate_warning_pct }
    });
  }

  // Latency check.
  if (h.p95_duration_ms && h.p95_duration_ms > thr.max_p95_ms) {
    alerts.push({
      severity: 'warning', alert_type: 'health_latency_spike',
      title: '[' + (h.workflow_name || wid) + '] p95 latency ' + Math.round(h.p95_duration_ms / 1000) + 's — over SLO',
      message: 'p95 execution duration exceeded SLO of ' + Math.round(thr.max_p95_ms / 1000) + 's. Latest window p95 = ' + Math.round(h.p95_duration_ms / 1000) + 's.',
      aggregation_key: 'health:latency:' + wid + ':' + nowHour,
      details: { workflow_id: wid, workflow_name: h.workflow_name, p95_ms: h.p95_duration_ms, threshold_ms: thr.max_p95_ms }
    });
  }
});

// === Endpoint analysis ===
const latestByEp = {};
ehealth.forEach(function (e) {
  if (!latestByEp[e.endpoint_name] || e.checked_at > latestByEp[e.endpoint_name].checked_at) {
    latestByEp[e.endpoint_name] = e;
  }
});
Object.keys(latestByEp).forEach(function (ep) {
  const e = latestByEp[ep];
  const thr = byScope.endpoint[ep] || defaults;
  if (e.status === 'down' && e.consecutive_failures >= thr.max_consecutive_down) {
    alerts.push({
      severity: 'critical', alert_type: 'health_endpoint_down',
      title: '[' + ep + '] Endpoint DOWN (' + e.consecutive_failures + ' consecutive failures)',
      message: 'Endpoint ' + e.endpoint_url + ' has been down for ' + e.consecutive_failures + ' consecutive checks. Last error: ' + (e.last_error || 'unknown') + '.',
      aggregation_key: 'health:endpoint_down:' + ep + ':' + nowHour,
      details: { endpoint_name: ep, endpoint_url: e.endpoint_url, consecutive_failures: e.consecutive_failures, last_error: e.last_error, status_code: e.status_code }
    });
  } else if (e.status === 'degraded') {
    alerts.push({
      severity: 'warning', alert_type: 'health_endpoint_degraded',
      title: '[' + ep + '] Endpoint returned non-success status',
      message: 'Endpoint responded with status ' + (e.status_code || 'unknown') + '. ' + (e.last_error || ''),
      aggregation_key: 'health:endpoint_degraded:' + ep + ':' + nowHour,
      details: { endpoint_name: ep, status_code: e.status_code, last_error: e.last_error }
    });
  }
});

return { json: { alerts: alerts, workflows_analyzed: Object.keys(latestByWf).length, endpoints_analyzed: Object.keys(latestByEp).length } };

const alerts = $input.item.json.alerts || [];
if (!alerts.length) return [{ json: { _no_alerts: true } }];
return alerts.map(function (a) { return { json: a }; });
